 40â†’public class ParameterListWrappingRule :
 41â†’    StandardRule(
 42â†’        id = "parameter-list-wrapping",
 43â†’        usesEditorConfigProperties =
 44â†’            setOf(
 45â†’                CODE_STYLE_PROPERTY,
 46â†’                INDENT_SIZE_PROPERTY,
 47â†’                INDENT_STYLE_PROPERTY,
 48â†’                MAX_LINE_LENGTH_PROPERTY,
 49â†’            ),
 50â†’    ) {
 51â†’    private var codeStyle = CODE_STYLE_PROPERTY.defaultValue
 52â†’    private var indentConfig = IndentConfig.DEFAULT_INDENT_CONFIG
 53â†’    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue
 54â†’
 55â†’    override fun beforeFirstNode(editorConfig: EditorConfig) {
 56â†’        codeStyle = editorConfig[CODE_STYLE_PROPERTY]
 57â†’        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 58â†’        indentConfig =
 59â†’            IndentConfig(
 60â†’                indentStyle = editorConfig[INDENT_STYLE_PROPERTY],
 61â†’                tabWidth = editorConfig[INDENT_SIZE_PROPERTY],
 62â†’            )
 63â†’        if (indentConfig.disabled) {
 64â†’            stopTraversalOfAST()
 65â†’        }
 66â†’    }
 67â†’
 68â†’    override fun beforeVisitChildNodes(
 69â†’        node: ASTNode,
 70â†’        autoCorrect: Boolean,
 71â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 72â†’    ) {
 73â†’        when (node.elementType) {
 74â†’            NULLABLE_TYPE -> wrapNullableType(node, emit, autoCorrect)
 75â†’            VALUE_PARAMETER_LIST -> {
 76â†’                if (node.needToWrapParameterList()) {
 77â†’                    wrapParameterList(node, emit, autoCorrect)
 78â†’                }
 79â†’            }
 80â†’        }
 81â†’    }
 82â†’
 83â†’    private fun wrapNullableType(
 84â†’        node: ASTNode,
 85â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 86â†’        autoCorrect: Boolean,
 87â†’    ) {
 88â†’        require(node.elementType == NULLABLE_TYPE)
 89â†’        node
 90â†’            .takeUnless {
 91â†’                // skip when max line length is not exceedd
 92â†’                (node.column - 1 + node.textLength) <= maxLineLength
 93â†’            }?.findChildByType(FUNCTION_TYPE)
 94â†’            ?.findChildByType(VALUE_PARAMETER_LIST)
 95â†’            ?.takeIf { it.findChildByType(VALUE_PARAMETER) != null }
 96â†’            ?.takeUnless { it.textContains('\n') }
 97â†’            ?.let {
 98â†’                node
 99â†’                    .children()
100â†’                    .forEach {
101â†’                        when (it.elementType) {
102â†’                            LPAR -> {
103â†’                                emit(
104â†’                                    it.startOffset,
105â†’                                    "Parameter of nullable type should be on a separate line (unless the type fits on a single line)",
106â†’                                    true,
107â†’                                )
108â†’                                if (autoCorrect) {
109â†’                                    it.upsertWhitespaceAfterMe(indentConfig.childIndentOf(node))
110â†’                                }
111â†’                            }
112â†’                            RPAR -> {
113â†’                                emit(it.startOffset, errorMessage(it), true)
114â†’                                if (autoCorrect) {
115â†’                                    it.upsertWhitespaceBeforeMe(indentConfig.parentIndentOf(node))
116â†’                                }
117â†’                            }
118â†’                        }
119â†’                    }
120â†’            }
121â†’    }
122â†’
123â†’    private fun ASTNode.needToWrapParameterList() =
124â†’        when {
125â†’            hasNoParameters() -> false
126â†’            codeStyle != ktlint_official && isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle() -> false
127â†’            codeStyle == ktlint_official && isPartOfFunctionLiteralStartingOnSameLineAsClosingParenthesisOfPrecedingReferenceExpression() ->
128â†’                false
129â†’            isFunctionTypeWrappedInNullableType() -> false
130â†’            textContains('\n') -> true
131â†’            codeStyle == ktlint_official && containsAnnotatedParameter() -> true
132â†’            exceedsMaxLineLength() -> true
133â†’            else -> false
134â†’        }
135â†’
136â†’    private fun ASTNode.hasNoParameters(): Boolean {
137â†’        require(elementType == VALUE_PARAMETER_LIST)
138â†’        return firstChildNode?.treeNext?.elementType == RPAR
139â†’    }
140â†’
141â†’    private fun ASTNode.isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle(): Boolean {
142â†’        require(elementType == VALUE_PARAMETER_LIST)
143â†’        return treeParent?.elementType == FUNCTION_LITERAL
144â†’    }
145â†’
146â†’    private fun ASTNode.isPartOfFunctionLiteralStartingOnSameLineAsClosingParenthesisOfPrecedingReferenceExpression(): Boolean {
147â†’        require(elementType == VALUE_PARAMETER_LIST)
148â†’        return firstChildLeafOrSelf()
149â†’            .let { startOfFunctionLiteral ->
150â†’                treeParent
151â†’                    ?.takeIf { it.elementType == FUNCTION_LITERAL }
152â†’                    ?.prevCodeLeaf()
153â†’                    ?.takeIf { it.treeParent.elementType == ElementType.VALUE_ARGUMENT_LIST }
154â†’                    ?.takeIf { it.treeParent.treeParent.elementType == ElementType.CALL_EXPRESSION }
155â†’                    ?.leaves()
156â†’                    ?.takeWhile { it != startOfFunctionLiteral }
157â†’                    ?.none { it.isWhiteSpaceWithNewline() }
158â†’                    ?: false
159â†’            }
160â†’    }
161â†’
162â†’    private fun ASTNode.isFunctionTypeWrappedInNullableType(): Boolean {
163â†’        require(elementType == VALUE_PARAMETER_LIST)
164â†’        return treeParent.elementType == FUNCTION_TYPE && treeParent?.treeParent?.elementType == NULLABLE_TYPE
165â†’    }
166â†’
167â†’    private fun ASTNode.containsAnnotatedParameter(): Boolean {
168â†’        require(elementType == VALUE_PARAMETER_LIST)
169â†’        return this.children()
170â†’            .filter { it.elementType == VALUE_PARAMETER }
171â†’            .any { it.isAnnotated() }
172â†’    }
173â†’
174â†’    private fun ASTNode.isAnnotated() =
175â†’        findChildByType(ElementType.MODIFIER_LIST)
176â†’            ?.children()
177â†’            .orEmpty()
178â†’            .any { it.elementType == ElementType.ANNOTATION_ENTRY }
179â†’
180â†’    private fun wrapParameterList(
181â†’        node: ASTNode,
182â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
183â†’        autoCorrect: Boolean,
184â†’    ) {
185â†’        node
186â†’            .children()
187â†’            .forEach { child -> wrapParameterInList(child, emit, autoCorrect) }
188â†’    }
189â†’
190â†’    private fun intendedIndent(child: ASTNode): String =
191â†’        when {
192â†’            // IDEA quirk:
193â†’            // fun <
194â†’            //     T,
195â†’            //     R> test(
196â†’            //     param1: T
197â†’            //     param2: R
198â†’            // )
199â†’            // instead of
200â†’            // fun <
201â†’            //     T,
202â†’            //     R> test(
203â†’            //         param1: T
204â†’            //         param2: R
205â†’            //     )
206â†’            child.treeParent.hasTypeParameterListInFront() -> -1
207â†’
208â†’            else -> 0
209â†’        }.let {
210â†’            if (child.elementType == VALUE_PARAMETER) {
211â†’                it + 1
212â†’            } else {
213â†’                it
214â†’            }
215â†’        }.let { indentLevelFix ->
216â†’            val indentLevel =
217â†’                indentConfig
218â†’                    .indentLevelFrom(child.treeParent.indent(false))
219â†’                    .plus(indentLevelFix)
220â†’            "\n" + indentConfig.indent.repeat(indentLevel)
221â†’        }
222â†’
223â†’    private fun wrapParameterInList(
224â†’        child: ASTNode,
225â†’        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
226â†’        autoCorrect: Boolean,
227â†’    ) {
228â†’        when (child.elementType) {
229â†’            LPAR -> {
230â†’                val prevLeaf = child.prevLeaf()
231â†’                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
232â†’                    emit(child.startOffset, errorMessage(child), true)
233â†’                    if (autoCorrect) {
234â†’                        prevLeaf.delete()
235â†’                    }
236â†’                }
237â†’            }
238â†’            VALUE_PARAMETER,
239â†’            RPAR,
240â†’            -> {
241â†’                // aiming for
242â†’                // ... LPAR
243â†’                // <line indent + indentSize> VALUE_PARAMETER...
244â†’                // <line indent> RPAR
245â†’                val intendedIndent = intendedIndent(child)
246â†’                val prevLeaf = child.prevLeaf()
247â†’                if (prevLeaf is PsiWhiteSpace) {
248â†’                    if (prevLeaf.getText().contains("\n")) {
249â†’                        // The current child is already wrapped to a new line. Checking and fixing the
250â†’                        // correct size of the indent is the responsibility of the IndentationRule.
251â†’                        return
252â†’                    } else {
253â†’                        // The current child needs to be wrapped to a newline.
254â†’                        emit(child.startOffset, errorMessage(child), true)
255â†’                        if (autoCorrect) {
256â†’                            // The indentation is purely based on the previous leaf only. Note that in
257â†’                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
258â†’                            // determines the final indentation. But if the indent rule is disabled then the
259â†’                            // indent of this rule is kept.
260â†’                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
261â†’                        }
262â†’                    }
263â†’                } else {
264â†’                    // Insert a new whitespace element in order to wrap the current child to a new line.
265â†’                    emit(child.startOffset, errorMessage(child), true)
266â†’                    if (autoCorrect) {
267â†’                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
268â†’                    }
269â†’                }
270â†’                // Indentation of child nodes need to be fixed by the IndentationRule.
271â†’            }
272â†’        }
273â†’    }
274â†’
275â†’    private fun ASTNode.exceedsMaxLineLength() = (column - 1 + textLength) > maxLineLength && !textContains('\n')
276â†’
277â†’    private fun errorMessage(node: ASTNode) =
278â†’        when (node.elementType) {
279â†’            LPAR -> """Unnecessary newline before "(""""
280â†’            VALUE_PARAMETER ->
281â†’                "Parameter should start on a newline"
282â†’            RPAR -> """Missing newline before ")""""
283â†’            else -> throw UnsupportedOperationException()
284â†’        }
285â†’
286â†’    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
287â†’        val parent = this.treeParent
288â†’        val typeParameterList =
289â†’            if (parent.elementType == PRIMARY_CONSTRUCTOR) {
290â†’                parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
291â†’            } else {
292â†’                parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
293â†’            }
294â†’        val typeListNode =
295â†’            typeParameterList
296â†’                ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
297â†’                ?: return false
298â†’        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
299â†’    }
300â†’}
301â†’
302â†’public val PARAMETER_LIST_WRAPPING_RULE_ID: RuleId = ParameterListWrappingRule().ruleId
303â†’

